import numpy as np

class ResidualBlockProjection:
    def __init__(self, d_in: int, d_out: int):
        self.need_projection = (d_in != d_out)

        # Main path: Linear(d_in, d_out) → ReLU → Linear(d_out, d_out)
        def xavier(fi, fo):
            lim = np.sqrt(6 / (fi + fo))
            return np.random.uniform(-lim, lim, (fi, fo))

        self.W1 = xavier(d_in, d_out)
        self.b1 = np.zeros(d_out)
        self.W2 = xavier(d_out, d_out)
        self.b2 = np.zeros(d_out)

        # Projection shortcut (only when d_in != d_out)
        if self.need_projection:
            self.W_proj = xavier(d_in, d_out)
            self.b_proj = np.zeros(d_out)

    def forward(self, x: np.ndarray) -> np.ndarray:
        # Main path
        h = np.maximum(0, x @ self.W1 + self.b1)  # (N, d_out) with ReLU
        fx = h @ self.W2 + self.b2                 # (N, d_out)

        # Shortcut
        if self.need_projection:
            shortcut = x @ self.W_proj + self.b_proj  # (N, d_out)
        else:
            shortcut = x  # identity (N, d_out)

        return np.maximum(0, fx + shortcut)
